import React from 'react';
import CouponGenerator from './CouponGenerator';

const AdminPanel = () => {
  return (
    <div className="admin-panel-simple">
      <div className="admin-container">
        <div className="admin-header-simple">
          <h1>🎫 Coupon Code Generator</h1>
          <p>Create promo codes for your advertising platform</p>
        </div>
        
        <CouponGenerator />
      </div>
    </div>
  );
};

export default AdminPanel;
